package com.veetu.vadagai.tenant;import com.veetu.vadagai.common.ApiResponse;import com.veetu.vadagai.tenant.TenantDtos.*;import com.veetu.vadagai.user.CurrentUserService;import jakarta.validation.Valid;import lombok.RequiredArgsConstructor;import org.springframework.security.access.prepost.PreAuthorize;import org.springframework.web.bind.annotation.*;import java.util.*;
@RestController @RequestMapping("/api/v1/tenants") @RequiredArgsConstructor public class TenantController{private final TenantService svc;private final CurrentUserService current;@GetMapping @PreAuthorize("hasAnyRole('OWNER','ADMIN')") ApiResponse<List<TenantResponse>> list(){return ApiResponse.ok("Tenants",svc.ownerTenants(current.get().getId()));}@PostMapping @PreAuthorize("hasRole('OWNER')") ApiResponse<TenantResponse> add(@Valid @RequestBody TenantRequest r){return ApiResponse.ok("Tenant added",svc.add(r));}}
